import base64
import requests
import uuid
import datetime
import xml.etree.ElementTree as ET
from urllib.parse import urlencode

def build_saml_request(destination_url, user_info):
    # Generate a unique ID for the SAML request
    request_id = '_' + str(uuid.uuid4())
    issue_instant = datetime.datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')

    # Construct the SAML Authentication Request XML
    saml_request_template = """
    <samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
                        xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
                        ID="{request_id}"
                        Version="2.0"
                        IssueInstant="{issue_instant}"
                        Destination="{destination_url}"
                        ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
                        AssertionConsumerServiceURL="{acs_url}">
        <saml:Issuer>{issuer}</saml:Issuer>
        <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified"
                            AllowCreate="true"/>
    </samlp:AuthnRequest>
    """

    # Safely format the XML with user-provided values
    saml_request = saml_request_template.format(
        request_id=request_id,
        issue_instant=issue_instant,
        destination_url=ET.Element('temp', {'url': destination_url}).attrib['url'],
        acs_url=ET.Element('temp', {'url': user_info['acs_url']}).attrib['url'],
        issuer=ET.Element('temp', {'url': user_info['issuer']}).attrib['url']
    )

    # Encode the SAML request
    encoded_saml_request = base64.b64encode(saml_request.encode('utf-8')).decode('utf-8')

    # Prepare the POST data
    post_data = {
        'SAMLRequest': encoded_saml_request,
        'RelayState': user_info.get('relay_state', '')
    }

    # Send the SAML request to the Identity Provider
    response = requests.post(destination_url, data=post_data)
    return response

